samples.mcp:
// scripts/smoke-coingecko-mcp.ts — D-9 spike
import { Client } from "@modelcontextprotocol/sdk/client";
import { StreamableHTTPClientTransport }
  from "@modelcontextprotocol/sdk/client/streamableHttp";

const t = new StreamableHTTPClientTransport(
  new URL("https://mcp.api.coingecko.com/mcp"),  // official public endpoint
);
const client = new Client({ name: "inalpha", version: "0.9" });
await client.connect(t);
const tools = await client.listTools();
// → 32 CoinGecko tools land on the orchestrator · zero glue code
